            row?.[3]?.toString().toLowerCase().includes(filter_invoice_customer) ||
            row?.[2]?.toString().toLowerCase().includes(filter_invoice_customer)

        // 🔹 Vendedor (con verificación de rol)
        const bySeller =
            userNickname === "vendedor"
                ? row?.[14]?.toString().toLowerCase().includes(userName)
                : !filter_seller ||
                row?.[14]?.toString().toLowerCase().includes(filter_seller)

        // 🔹 Año (col [5])
        const year =
            (row?.[5] || "").toString().split("-").pop()?.trim() || ""

        const byYear =
            !filter_year || year === filter_year

        // 🔹 Estado (col [8])
        const byStatus =
            !filter_status ||
            row?.[8]?.toString().toLowerCase().includes(filter_status)

        return byCustomer && bySeller && byYear && byStatus
    })
    .slice(0, 100) // 🛑 máximo 100 items, sin discusión

