// ==================
const headers = [
    'id',
    'personId',
    'personName',
    'consecutive',
    'qr',
    'date',
    'dueDate',
    'expirationDays',
    'status',
    'stateDian',
    'totalAmount',
    'paymentAmount',
    'balanceAmount',
    'personIdSeller',
    'personNameSeller'
]

return filteredRows.map((row, index) => {

